      function CF_EMPLOYMENTFormula return nUMBER is
  V_BOOL BOOLEAN;
  v_COND NUMBER;
 	V_WORKING_INS_REDUCTION	 NUMBER;
  V_WORK_INS_CHILD_INCR		 NUMBER;
 	V_WORK_INS_SECTOR				 VARCHAR2(1);
 	
begin

  v_BOOL := Find_SPECIAL_FACT_SUBTYPE(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
			 0,:p_form_id,
			 '00001',
			 '00019',--ΕΡΓΑΣΙΑ (ΕΞΗΡΤΗΜΕΝΗ - ΔΗΜ. ΤΟΜΕΑ)
			 '00033');--ΣΥΝΕΧΙΣΗ ΕΡΓΑΣΙΑΣ
  
  SELECT WORKING_INS_REDUCTION,
  			 WORK_INS_CHILD_INCR,
 				 WORK_INS_SECTOR
 	INTO V_WORKING_INS_REDUCTION,
  		 V_WORK_INS_CHILD_INCR,
 			 V_WORK_INS_SECTOR
  FROM PEN_ACCOUNT
  WHERE ACCOUNT_NO =  :P_ACCOUNT_NO_KYRIA;
  
  IF V_BOOL =TRUE AND NVL(V_WORKING_INS_REDUCTION,0) != 0 THEN 
  	 V_COND :=1;
  ELSIF V_BOOL =TRUE THEN
  	 V_COND :=2;
  ELSE
  	 V_COND :=3;
  END IF;	 
  
  :CP_1:=V_WORK_INS_SECTOR;
  
  RETURN V_COND;
  EXCEPTION WHEN OTHERS THEN RETURN NULL;

end;

      function CF_SEX_DESCRFormula return Char is

V_SEX VARCHAR2(1);

BEGIN

  SELECT A.SEX
  INTO V_SEX
  FROM REG_INSURED A
  WHERE A.INSURED_ID = :P_INSURED_ID;

  IF V_SEX = 'Α' THEN 
   RETURN 'ΤΟΥ';
  ELSE 
  	RETURN 'ΤΗΣ';
  END IF;
END;

      function CF_ANNOUNCEMENTFormula return Char is

V_BRANCH_CODE VARCHAR2(5);
V_BRANCH_NAME VARCHAR2(50);

BEGIN
  V_BRANCH_CODE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
			 0,:p_form_id,'00001','00172','00247');
  IF V_BRANCH_CODE IS NULL THEN
  	V_BRANCH_CODE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
			 0,:p_form_id,'00001','00069','00247');			 
  END IF;
  
  IF V_BRANCH_CODE IS NULL THEN
	    V_BRANCH_CODE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
				 0,0,'00001','01069','00247');   
		END IF;		 
  
IF V_BRANCH_CODE IS NOT NULL THEN
     SELECT A.BRANCH_NAME
	   INTO V_BRANCH_NAME
	   FROM COM_ORG_BRANCHES A
	   WHERE A.BRANCH_CODE = V_BRANCH_CODE;
ELSE
	V_BRANCH_NAME:= ' ';
END IF;

RETURN V_BRANCH_NAME;
EXCEPTION WHEN OTHERS THEN RETURN NULL;
END;

      function CF_PRESUMED_WAGEFormula return Number is

v_amount number;

CURSOR cur_presumed is 
SELECT A.PRESUMED_WAGES
FROM COM_CURRENT_PRESUMED_WAGES A
WHERE A.PREWAG_INSURANCE_CLASS = :INSURANCE_CLASS
AND A.FROM_DAILY_WAGES <= ROUND(:NOTICE_TOTAL_SALARY/:NOTICE_TOTAL_DAYS,2)
AND (A.TO_DAILY_WAGES >= ROUND(:NOTICE_TOTAL_SALARY/:NOTICE_TOTAL_DAYS,2)
     OR :INSURANCE_CLASS = 28)
AND A.EFFECTIVENESS_START_DATE <= TO_DATE('31'||'12'||:PERIOD_YEAR_TO,'DD/MM/RRRR') 
ORDER BY A.EFFECTIVENESS_START_DATE DESC;

begin
--  insert into error_debug values ('PW',':INSURANCE_CLASS',:INSURANCE_CLASS);
--  insert into error_debug values ('PW',':NOTICE_TOTAL_SALARY',:NOTICE_TOTAL_SALARY);
--  insert into error_debug values ('PW',':NOTICE_TOTAL_DAYS',:NOTICE_TOTAL_DAYS);
--  insert into error_debug values ('PW',':PERIOD_YEAR_TO',:PERIOD_YEAR_TO);
--  commit;
  if :PERIOD_YEAR_TO is not null then
  if nvl(:NOTICE_TOTAL_DAYS,0)!= 0 then 
	  open cur_presumed;
	  fetch cur_presumed
	  into v_amount;
	  close cur_presumed;
	  
--  insert into error_debug values ('PW',':v_amount',v_amount);
--  commit;
  
  else 
  	v_amount:=null;
  end if;
  end if;
  return v_amount;
end;

      function CF_PROCCESS_IDFormula return Number is

V_PROCESS_ID NUMBER;

CURSOR CUR_PROCESS IS
SELECT A.PROCESS_ID
FROM PEN_SUMMARIZATION_PER_INSURED A
WHERE A.INSURED_ID = :P_INSURED_ID
ORDER BY A.PROCESS_ID DESC;

begin
	
	OPEN CUR_PROCESS;
	FETCH CUR_PROCESS
	INTO V_PROCESS_ID;
	CLOSE CUR_PROCESS;
	
  :P_PROCESS_ID:=V_PROCESS_ID;
  RETURN :P_PROCESS_ID;
end;

      function CF_YEARS_USEDFormula return Char is

TYPE T_YEARS_USED IS TABLE OF NUMBER INDEX BY BINARY_INTEGER;
YEARS T_YEARS_USED ;
I NUMBER:=1;
LINE VARCHAR2(200) :=''; --CONTAINTS YEARS WITH FORM 1999,2000,2001

CURSOR CUR_YEARS_USED IS
SELECT A.YEAR_USED
FROM PEN_SUMMAR_CLASS_YEARS A 
WHERE A.PROCESS_ID = :P_PROCESS_ID;

begin
  
  OPEN CUR_YEARS_USED;

   LOOP
	  FETCH CUR_YEARS_USED
	  INTO YEARS(I);
	  I:= I+1;
	  EXIT WHEN CUR_YEARS_USED%NOTFOUND;  
   END LOOP;

  FOR K IN 1..YEARS.COUNT LOOP
  if k!=years.count then 
     LINE := LINE || TO_CHAR(YEARS(K)) || ',';     
  else
    LINE := LINE || TO_CHAR(YEARS(K));     
  end if;
  END LOOP;
  
  CLOSE CUR_YEARS_USED;
  
  RETURN LINE;
  
end;

      FUNCTION CF_FINAL_PEN_AMOUNTFormula RETURN NUMBER IS

V_INS_REDUCTION NUMBER;
V_WORK_INS_CHILD_INCR NUMBER;

CURSOR cur_amount IS
SELECT WORKING_INS_REDUCTION, WORK_INS_CHILD_INCR
FROM PEN_ACCOUNT
WHERE ACCOUNT_NO =  :P_ACCOUNT_NO_KYRIA;

BEGIN
  OPEN cur_amount;
  FETCH cur_amount
  INTO V_INS_REDUCTION,
       V_WORK_INS_CHILD_INCR;
  CLOSE cur_amount;
  
  RETURN :P_PENSION_AMOUNT -NVL(V_INS_REDUCTION,0) + NVL(V_WORK_INS_CHILD_INCR,0); 
END;

      function CF_PERSON_NAMEFormula return Char is

  v_Psv_user_id VARCHAR2(15);
  v_Person_Name VARCHAR2(100);

	Cursor cur_Psv_user_id is 
	SELECT Created_By
	FROM   PEN_ANALOGIST_ISODYNAMO_HD
	WHERE  1=1
	AND    PEN_ANALOGIST_ISODYNAMO_HD.INS_INSURED_ID    = :P_INSURED_ID
	AND    PEN_ANALOGIST_ISODYNAMO_HD.DEC_INCR_SEQ_NO   = :P_DEC_INCR_SEQ_NO
	AND    PEN_ANALOGIST_ISODYNAMO_HD.DT_DEC_UNIT_CODE  = :P_DT_DEC_UNIT_CODE
	AND    PEN_ANALOGIST_ISODYNAMO_HD.DT_DECISION_YEAR  = :P_DT_DECISION_YEAR
	 ;

begin
   --Psv_User_Id    := Sec_Appl_Pkg.Get_Current_User(:P_Login_Id);
   
   	OPEN cur_Psv_user_id;
	  FETCH cur_Psv_user_id
	  INTO v_Psv_user_id;
	  CLOSE cur_Psv_user_id;

    SELECT PERSON_SURNAME || ' ' ||PERSON_NAME
    INTO V_PERSON_NAME
    FROM SEC_USERS  
    WHERE USER_ID = v_Psv_user_id;

    RETURN V_PERSON_NAME; 
   
    EXCEPTION WHEN OTHERS THEN RETURN NULL;
end;

