      function CF_25aplasioFormula return Number is

v_amount number;

CURSOR cur_presumed is 
SELECT A.PRESUMED_WAGES
FROM COM_CURRENT_PRESUMED_WAGES A
WHERE A.PREWAG_INSURANCE_CLASS = :INSURANCE_CLASS
AND A.EFFECTIVENESS_START_DATE <= :p_acc_start_date
ORDER BY A.EFFECTIVENESS_START_DATE DESC;

begin
  
 
	  open cur_presumed;
	  fetch cur_presumed
	  into v_amount;
	  close cur_presumed;
 
  return (25*v_amount);
end;

