      function CF_20Formula return Char is
V_DURATION VARCHAR2(50);
V_LHXH	   VARCHAR2(50);  
begin
	
	---- ΠΡΟΣΘΗΚΗ ΑΠΟ 12/7/2021 SPAP ΣΕ ΑΙΤΗΣΗ ΑΠΟ Σ.ΒΑΚΛΑΤΖΗ ΝΑ ΜΗΝ ΕΜΦΑΝΙΖΕΤΑΙ ΤΟ ΚΕΙΜΕΝΟ ΕΑΝ Η ΗΜΝΙΑ ΛΗΞΗΣ ΕΙΝΑΙ ΠΡΟΓΕΝΕΣΤΕΡΗ ΑΠΟ ΤΗΝ ΗΜΝΙΑ ΚΑΤΑΒΟΛΗΣ
	v_LHXH := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
					 0,:p_form_id,'00001','01635','00588');
	
	IF v_LHXH IS NULL THEN
  	v_LHXH := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
					 0,:p_form_id,'00001','00635','00588');
	END IF;
	
	---- ΕΛΕΓΧΟΣ ΕΙΔΙΚΗΣ ΠΛΗΡΟΦΟΡΙΑΣ ΕΡΓΑΣΙΑΣ 
  v_DURATION := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
					 0,:p_form_id,'00001','01635','00637');
	
	IF V_DURATION IS NULL THEN
  	v_DURATION := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
					 0,:p_form_id,'00001','00635','00637');
	END IF;


  
  IF TO_DATE(v_LHXH,'DD/MM/YYYY') < :P_PAYMENT_START_DATE THEN
  	RETURN '' ;
  ELSE  
    --COMBAT_dEBUGING('v_DURATION = '||v_DURATION, 'CHRYS_REPORTS');
    return v_DURATION;
  END IF;
  
  RETURN '';
END;

      function CF_21Formula return Number is
V_NUM	  NUMBER;
V_NUM_1	NUMBER;
V_NUM_2	NUMBER;

CURSOR CUR IS
SELECT  ((sum(NVL(MONTH_INCOME_INFLATED,0)+NVL(RETRO_AMT_INFLATED,0))*25)/sum(NVL(MONTH_DAYS,0)))  
FROM PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACCOUNT_NO_KYRIA; 

CURSOR CUR_1 IS
SELECT   NVL(POSOSTO_ANAPL,0)+ NVL(ADAPOD_PERCENT_KSB,0)
FROM  PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACCOUNT_NO_KYRIA;

CURSOR CUR_2 IS
SELECT ADAPODOTIKH_AMT
FROM   PEN_CALC_ADAPOD_RESULTS
WHERE  ACCOUNT_NO = :P_ACCOUNT_NO_KYRIA;

begin
  
  OPEN CUR;
  FETCH CUR 
  INTO V_NUM;
  CLOSE CUR;
  
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
  OPEN CUR_2;
  FETCH CUR_2 
  INTO V_NUM_2;
  CLOSE CUR_2;
  
  
  IF V_NUM_2 IS NOT NULL AND V_NUM_2 != 0 THEN
  	RETURN V_NUM_2;
  ELSE
	  RETURN (NVL(V_NUM,0)*NVL(V_NUM_1,0))/100;
  END IF;
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

      function CF_22Formula return Number is
V_NUM	  NUMBER;
V_NUM_1	NUMBER;
V_NUM_2	NUMBER;

CURSOR CUR IS
SELECT  ((sum(NVL(MONTH_INCOME_INFLATED,0)+NVL(RETRO_AMT_INFLATED,0))*25)/sum(NVL(MONTH_DAYS,0)))  
FROM PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACCOUNT_NO_KYRIA; 

CURSOR CUR_1 IS
SELECT   NVL(POSOSTO_ANAPL,0)+ NVL(ADAPOD_PERCENT_KSB,0)
FROM  PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACCOUNT_NO_KYRIA;

CURSOR CUR_2 IS
SELECT ADAPODOTIKH_AMT
FROM   PEN_CALC_ADAPOD_RESULTS
WHERE  ACCOUNT_NO = :P_ACCOUNT_NO_KYRIA;

begin
  
  OPEN CUR;
  FETCH CUR 
  INTO V_NUM;
  CLOSE CUR;
  
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
  OPEN CUR_2;
  FETCH CUR_2 
  INTO V_NUM_2;
  CLOSE CUR_2;
  
  
  IF V_NUM_2 IS NOT NULL AND V_NUM_2 != 0 THEN
  	RETURN V_NUM_2;
  ELSE
	  RETURN (NVL(V_NUM,0)*NVL(V_NUM_1,0))/100;
  END IF;
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

