function AfterPForm return boolean is
cursor c1 is SELECT COM_ORG_BRANCHES.ADDRESS_STREET||' '||COM_ORG_BRANCHES.ADDRESS_NO||', '||COM_ORG_BRANCHES.ZIP_CODE||', '||COM_ORG_BRANCHES.CITY, COM_ORG_BRANCHES.PHONE_NUMBER, COM_ORG_BRANCHES.BRANCH_NAME FROM PEN_ANALOGIST_ISODYNAMO_HD, COM_ORG_BRANCHES WHERE PEN_ANALOGIST_ISODYNAMO_HD.DT_DEC_UNIT_CODE = :P_DT_DEC_UNIT_CODE AND PEN_ANALOGIST_ISODYNAMO_HD.DT_DECISION_YEAR = :P_DT_DECISION_YEAR AND PEN_ANALOGIST_ISODYNAMO_HD.DEC_INCR_SEQ_NO = :P_DEC_INCR_SEQ_NO AND PEN_ANALOGIST_ISODYNAMO_HD.STATUS = '1' AND COM_ORG_BRANCHES.BRANCH_CODE = PEN_ANALOGIST_ISODYNAMO_HD.DT_DEC_UNIT_CODE ;
CURSOR CUR_KYRIA IS SELECT D.PAI_PDTA_APPLICATION_UNIT_CODE, D.PAI_PDTA_APPLICATION_YEAR , D.PAI_APPLICATION_INCR_SEQ_NO FROM PEN_ACCOUNT C, PEN_DECISION_INSTANCE D, PEN_ANALOGIST_ISODYNAMO_DTL A WHERE A.INS_INSURED_ID = :P_INSURED_ID AND A.REF_SID = :P_SID AND A.PRODUCT_CODE = '00011' AND D.DT_DOCUMENT_TYPE_DEC_CODE = '1' AND D.DT_DEC_UNIT_CODE = A.DT_DEC_UNIT_CODE AND D.DT_DECISION_YEAR = A.DT_DECISION_YEAR AND D.DEC_INCR_SEQ_NO = A.DEC_INCR_SEQ_NO AND D.DT_DOCUMENT_TYPE_DEC_CODE = C.DI_DT_DOCUMENT_TYPE_DEC_CODE AND D.DEC_UNIT_CODE_SR = C.DI_DT_DEC_UNIT_CODE AND D.DECISION_YEAR_SR = C.DI_DT_DECISION_YEAR AND D.INCR_SEQ_NO_SR = C.DI_DEC_INCR_SEQ_NO;
CURSOR CUR_ETEAEP IS SELECT D.PAI_PDTA_APPLICATION_UNIT_CODE, D.PAI_PDTA_APPLICATION_YEAR , D.PAI_APPLICATION_INCR_SEQ_NO FROM PEN_ACCOUNT C, PEN_DECISION_INSTANCE D, PEN_ANALOGIST_ISODYNAMO_DTL A WHERE A.INS_INSURED_ID = :P_INSURED_ID AND A.REF_SID = :P_SID AND A.PRODUCT_CODE = '00012' AND D.DT_DOCUMENT_TYPE_DEC_CODE = '1' AND D.DT_DEC_UNIT_CODE = A.DT_DEC_UNIT_CODE AND D.DT_DECISION_YEAR = A.DT_DECISION_YEAR AND D.DEC_INCR_SEQ_NO = A.DEC_INCR_SEQ_NO AND D.DT_DOCUMENT_TYPE_DEC_CODE = C.DI_DT_DOCUMENT_TYPE_DEC_CODE AND D.DEC_UNIT_CODE_SR = C.DI_DT_DEC_UNIT_CODE AND D.DECISION_YEAR_SR = C.DI_DT_DECISION_YEAR AND D.INCR_SEQ_NO_SR = C.DI_DEC_INCR_SEQ_NO;
CURSOR CUR_ACCOUNT_EFAPAX IS SELECT D.PAI_PDTA_APPLICATION_UNIT_CODE, D.PAI_PDTA_APPLICATION_YEAR , D.PAI_APPLICATION_INCR_SEQ_NO FROM PEN_ACCOUNT C, PEN_DECISION_INSTANCE D, PEN_ANALOGIST_ISODYNAMO_DTL A WHERE A.INS_INSURED_ID = :P_INSURED_ID AND A.REF_SID = :P_SID AND A.PRODUCT_CODE = '00013' AND D.DT_DOCUMENT_TYPE_DEC_CODE = '1' AND D.DT_DEC_UNIT_CODE = A.DT_DEC_UNIT_CODE AND D.DT_DECISION_YEAR = A.DT_DECISION_YEAR AND D.DEC_INCR_SEQ_NO = A.DEC_INCR_SEQ_NO AND D.DT_DOCUMENT_TYPE_DEC_CODE = C.DI_DT_DOCUMENT_TYPE_DEC_CODE AND D.DEC_UNIT_CODE_SR = C.DI_DT_DEC_UNIT_CODE AND D.DECISION_YEAR_SR = C.DI_DT_DECISION_YEAR AND D.INCR_SEQ_NO_SR = C.DI_DEC_INCR_SEQ_NO;
-------------- BEGIN begin
open c1; fetch c1 into :P_BRANCH_ADDRESS, :P_BRANCH_TEL, :P_BRANCH_NAME ; close c1;
OPEN CUR_KYRIA; FETCH CUR_KYRIA INTO :P_APPL_UNIT_CODE_KYR, :P_APPL_YEAR_KYR, :P_APPL_INCR_SEQ_NO_KYR; CLOSE CUR_KYRIA;
OPEN CUR_ETEAEP; FETCH CUR_ETEAEP INTO :P_APPL_UNIT_CODE_EPI, :P_APPL_YEAR_EPI, :P_APPL_INCR_SEQ_NO_EPI; CLOSE CUR_ETEAEP;
OPEN CUR_ACCOUNT_EFAPAX; FETCH CUR_ACCOUNT_EFAPAX INTO :P_APPL_UNIT_CODE_EF, :P_APPL_YEAR_EF, :P_APPL_INCR_SEQ_NO_EF; CLOSE CUR_ACCOUNT_EFAPAX;
return (TRUE); end;

