      function cf_EPIK_amount_bFormula return Number 
is

-- CHRYS 4/7/2022

CURSOR CUR_AMOUNT_B IS
SELECT DISTINCT AMOUNT_B
FROM	PEN_CALC_ADAPOD_RESULTS_ETEAEP
WHERE ACCOUNT_NO = :P_ACCOUNT_NO_EPIK
AND		NVL(AMOUNT_B,0) != 0;

-- END CHRYS 4/7/2022

  cursor c1
  is
    select distinct
           round(a.total_contributions_amt_b/(a.ranta * 12),2) poso_b
      from pen_calc_adapod_results_eteaep a
     where a.account_no  = :P_ACCOUNT_NO_EPIK -- CHRYS 28/8/2018 :P_INSURED_ID
       and nvl(a.total_contributions_amt_b,0) <> 0;
  
  v_amount_b number;

CURSOR CUR_TOTAL_CONTRIBUTIONS IS
SELECT DISTINCT TOTAL_CONTRIBUTIONS_AMT_B
FROM	PEN_CALC_ADAPOD_RESULTS_ETEAEP
WHERE ACCOUNT_NO = :P_ACCOUNT_NO_EPIK
AND		YEAR >= 2015;
  

begin
	
IF PENBAT_FIND_PRODUCT_CODE (:P_ACCOUNT_NO_EPIK) = '00012' THEN

		OPEN	CUR_TOTAL_CONTRIBUTIONS;
		FETCH	CUR_TOTAL_CONTRIBUTIONS
		INTO V_AMOUNT_B;
		CLOSE CUR_TOTAL_CONTRIBUTIONS;	
   	RETURN V_AMOUNT_B;

END IF;

IF PENBAT_FIND_PRODUCT_CODE (:P_ACCOUNT_NO_EPIK) = '00015' THEN
   open c1;
   fetch c1 into v_amount_b;
   close c1;
   
	IF V_AMOUNT_B != 0 THEN
		RETURN V_AMOUNT_B;
	ELSE
		OPEN	CUR_AMOUNT_B;
		FETCH	CUR_AMOUNT_B
		INTO V_AMOUNT_B;
		CLOSE CUR_AMOUNT_B;	
   	RETURN V_AMOUNT_B;
  END IF;
END IF;

RETURN (0);
end;

