      function CF_MIN_MAX_DATESFormula return Char is

CURSOR	CUR_DATES IS
SELECT 	MIN(	TO_DATE('01'||LTRIM(LPAD(A.MONTH,2,0))||A.YEAR, 'DDMMRRRR')),  MAX(LAST_DAY(	TO_DATE('01'||LTRIM(LPAD(A.MONTH,2,0))||A.YEAR, 'DDMMRRRR')))  
FROM 		PEN_NATIONAL_MONTH_SALARY_DTL A, PEN_DECISION_INSTANCE B, PEN_ACCOUNT C
WHERE 	A.STATUS = '1'
AND			A.INS_INSURED_ID = :P_INSURED_ID
AND			A.PDTA_APPLICATION_UNIT_CODE = B.PAI_PDTA_APPLICATION_UNIT_CODE
AND			A.PDTA_APPLICATION_YEAR = B.PAI_PDTA_APPLICATION_YEAR
AND			A.APPLICATION_INCR_SEQ_NO = B.PAI_APPLICATION_INCR_SEQ_NO
AND			B.PAI_PDTA_DOC_TYPE_APPL_CODE = '00001'
AND			B.DOCUMENT_TYPE_DEC_CODE_SR = C.DI_DT_DOCUMENT_TYPE_DEC_CODE 
AND			B.DEC_UNIT_CODE_SR = C.DI_DT_DEC_UNIT_CODE
AND			B.DECISION_YEAR_SR = C.DI_DT_DECISION_YEAR
AND			B.INCR_SEQ_NO_SR = C.DI_DEC_INCR_SEQ_NO
AND     C.ACCOUNT_NO = :P_ACCOUNT_NO_KYRIA;

begin

OPEN	CUR_DATES;
FETCH	CUR_DATES
INTO	:CP_MIN_DATE,
			:CP_MAX_DATE;
CLOSE	CUR_DATES;

-- 	:CP_MIN_DATE := :SYN_INSURANCE_FROM;
--   :CP_MAX_DATE:= :SYN_INSURANCE_TO;
  RETURN (:CP_MIN_DATE);
  EXCEPTION WHEN OTHERS THEN RETURN NULL;
end;

