 --- :CP_YY_EFAPAX := :CP_YEARS_SUM ||' Ετη '||:CP_YEARS_SUM ||' Μήνες '||:CP_YEARS_SUM ||' Ημέρες '; OXI APO EDW ALLA APO EFKA_DAYS_DTL
