      function CF_SUM_XRONOI_KY_EPIKFormula return Char is

CURSOR C1 IS
SELECT MIN(MIN_DATE) MIN_DATE, MAX(MAX_DATE) MAX_DATE,  SUM(SUM_YY) SUM_YY, SUM(SUM_MM) SUM_MM, SUM(SUM_DD) SUM_DD
FROM 
(
SELECT 
       DATE_FROM MIN_DATE, 
       DATE_TO MAX_DATE,
       EE SUM_YY,
       MM SUM_MM,
       HH SUM_DD
FROM PEN_EFKA_DAYS_HDR A,
     PEN_EFKA_DAYS_DLT B
WHERE A.INSURED_ID = B.INSURED_ID
AND   A.INSURED_ID = :P_INSURED_ID
AND  (( B.PDTA_APPLICATION_UNIT_CODE = :P_APPL_UNIT_CODE    AND A.PDTA_APPLICATION_UNIT_CODE =  B.PDTA_APPLICATION_UNIT_CODE)  or (B.PDTA_APPLICATION_UNIT_CODE IS NULL AND 1=1))
AND  (( B.PDTA_APPLICATION_YEAR      = :P_APPL_YEAR         AND A.PDTA_APPLICATION_YEAR      =  B.PDTA_APPLICATION_YEAR     )  or (B.PDTA_APPLICATION_YEAR      IS NULL AND 1=1))                                                                                                                           
AND  (( B.APPLICATION_INCR_SEQ_NO    = :P_APPL_INCR_SEQ_NO  AND A.APPLICATION_INCR_SEQ_NO    =  B.APPLICATION_INCR_SEQ_NO   )  or (B.APPLICATION_INCR_SEQ_NO    IS NULL AND 1=1))
AND   :p_application_efka_days = 1
AND TEXT NOT LIKE '%ΣΥΝ%'
)
;

CURSOR C2 IS
SELECT MIN(MIN_DATE) MIN_DATE, MAX(MAX_DATE) MAX_DATE,  SUM(SUM_YY) SUM_YY, SUM(SUM_MM) SUM_MM, SUM(SUM_DD) SUM_DD
FROM 
(
SELECT 
       DATE_FROM MIN_DATE, 
       DATE_TO MAX_DATE,
       EE SUM_YY,
       MM SUM_MM,
       HH SUM_DD
FROM PEN_EFKA_DAYS_HDR A,
     PEN_EFKA_DAYS_DLT B
WHERE A.INSURED_ID = B.INSURED_ID
AND   A.INSURED_ID = :P_INSURED_ID
AND  (( B.PDTA_APPLICATION_UNIT_CODE = :P_APPL_UNIT_CODE    AND A.PDTA_APPLICATION_UNIT_CODE =  B.PDTA_APPLICATION_UNIT_CODE)  or (B.PDTA_APPLICATION_UNIT_CODE IS NULL AND 1=1))
AND  (( B.PDTA_APPLICATION_YEAR      = :P_APPL_YEAR         AND A.PDTA_APPLICATION_YEAR      =  B.PDTA_APPLICATION_YEAR     )  or (B.PDTA_APPLICATION_YEAR      IS NULL AND 1=1))                                                                                                                           
AND  (( B.APPLICATION_INCR_SEQ_NO    = :P_APPL_INCR_SEQ_NO  AND A.APPLICATION_INCR_SEQ_NO    =  B.APPLICATION_INCR_SEQ_NO   )  or (B.APPLICATION_INCR_SEQ_NO    IS NULL AND 1=1))
AND   :p_application_efka_days = 1
AND TEXT NOT LIKE '%ΣΥΝ%'
)
;


CURSOR C3 IS
SELECT MIN(MIN_DATE) MIN_DATE, MAX(MAX_DATE) MAX_DATE,  SUM(SUM_YY) SUM_YY, SUM(SUM_MM) SUM_MM, SUM(SUM_DD) SUM_DD
FROM 
(
SELECT 
       DATE_FROM MIN_DATE, 
       DATE_TO MAX_DATE,
       EE SUM_YY,
       MM SUM_MM,
       HH SUM_DD
FROM PEN_EFKA_DAYS_HDR A,
     PEN_EFKA_DAYS_DLT B
WHERE A.INSURED_ID = B.INSURED_ID
AND   A.INSURED_ID = :P_INSURED_ID
AND  (( B.PDTA_APPLICATION_UNIT_CODE = :P_APPL_UNIT_CODE    AND A.PDTA_APPLICATION_UNIT_CODE =  B.PDTA_APPLICATION_UNIT_CODE)  or (B.PDTA_APPLICATION_UNIT_CODE IS NULL AND 1=1))
AND  (( B.PDTA_APPLICATION_YEAR      = :P_APPL_YEAR         AND A.PDTA_APPLICATION_YEAR      =  B.PDTA_APPLICATION_YEAR     )  or (B.PDTA_APPLICATION_YEAR      IS NULL AND 1=1))                                                                                                                           
AND  (( B.APPLICATION_INCR_SEQ_NO    = :P_APPL_INCR_SEQ_NO  AND A.APPLICATION_INCR_SEQ_NO    =  B.APPLICATION_INCR_SEQ_NO   )  or (B.APPLICATION_INCR_SEQ_NO    IS NULL AND 1=1))
AND   :p_application_efka_days = 1
AND TEXT NOT LIKE '%ΣΥΝ%'
)
;


L_YY_KYR NUMBER:=0;
L_MM_KYR NUMBER:=0;
L_DD_KYR NUMBER:=0;

L_YY_EPI NUMBER:=0;
L_MM_EPI NUMBER:=0;
L_DD_EPI NUMBER:=0;

L_YY_EF  NUMBER:=0;
L_MM_EF  NUMBER:=0;
L_DD_EF  NUMBER:=0;

begin
	
  OPEN  C1;
  FETCH C1 INTO :CP_MIN_DATE_KYRIA, :CP_MAX_DATE_KYRIA, L_YY_KYR, L_MM_KYR, L_DD_KYR;
  CLOSE C1;
  
	SELECT TO_CHAR(
				         ROUND((nvl(L_YY_KYR*300,0) + 
				                nvl(L_MM_KYR*25,0)  +
				                nvl(L_DD_KYR,0))/300,2)
				         )||' Ετη'  INTO :CP_YY_KYRIA FROM DUAL;
  
  OPEN  C2;
  FETCH C2 INTO :CP_MIN_DATE_EPIK, :CP_MAX_DATE_EPIK, L_YY_EPI, L_MM_EPI, L_DD_EPI;
  CLOSE C2;
  
  SELECT TO_CHAR(
				         ROUND((nvl(L_YY_EPI*300,0) + 
				                nvl(L_MM_EPI*25,0)  +
				                nvl(L_DD_EPI,0))/300,2)
				         )||' Ετη'  INTO :CP_YY_EPIK FROM DUAL;
  
  
  OPEN  C3;
  FETCH C3 INTO :CP_MIN_DATE_EFAPAX, :CP_MAX_DATE_EFAPAX, L_YY_EF, L_MM_EF, L_DD_EF;
  CLOSE C3;
  
  SELECT TO_CHAR(
				         ROUND((nvl(L_YY_EF*300,0) + 
				                nvl(L_MM_EF*25,0)  +
				                nvl(L_DD_EF,0))/300,2)
				         )||' Ετη'  INTO :CP_YY_EFAPAX FROM DUAL;
  
  
  return (:CP_YY_KYRIA);
exception when others then return null;
	
end;

