      function CF_POSA_ENSOMATOSHSFormula return Number is

CURSOR C1 IS
SELECT AMOUNT
FROM   PEN_QT_PER_BE_CC_PER_ACCOUNT A
WHERE  A.ACC_ACCOUNT_NO = :P_ACCOUNT_NO_KYRIA
AND    A.CP_CALCULATION_PARAMETER_CODE = 'ANIS2';
	
CURSOR C2 IS
SELECT AMOUNT
FROM   PEN_QT_PER_BE_CC_PER_ACCOUNT A
WHERE  A.ACC_ACCOUNT_NO = :P_ACCOUNT_NO_EPIK
AND    A.CP_CALCULATION_PARAMETER_CODE = 'ANIT2';
	

CURSOR C3 IS
SELECT AMOUNT
FROM   PEN_QT_PER_BE_CC_PER_ACCOUNT A
WHERE  A.ACC_ACCOUNT_NO = :P_ACCOUNT_NO_EFAPAX
AND    A.CP_CALCULATION_PARAMETER_CODE = 'ANEF2';

CURSOR C4 IS
 SELECT   A.KEFALAIO_ENSOMATOSIS ,
          A.METAFEROMENO_KEFALAIO ,
          ROUND(A.ETH_ANAGNORISIS,5),
          A.POSO_EPISTROFIS
					--,A.SID
   FROM   PEN_ANALOGIST_ISODYNAMO_HD A					
  WHERE   A.STATUS = '1'
  AND     A.SID            = :P_SID
  AND     A.INS_INSURED_ID = :P_INSURED_ID; 


begin

	OPEN  C1;
	FETCH C1 INTO :CP_ENSOMATOSH_KYRIAS;
	CLOSE C1;
	
	OPEN  C2;
	FETCH C2 INTO :CP_ENSOMATOSH_EPIK;
	CLOSE C2;
	
	OPEN  C3;
	FETCH C3 INTO :CP_ENSOMATOSH_EFAPAX;
	CLOSE C3;
	             
  OPEN  C4;
	FETCH C4 INTO 
	              :CP_SYNOLIKO_POSO_KE,
	              :CP_AI_EE_DO,
	              :CP_XRONOS_ANAGNORISHS,
	              :CP_YPOLEIPOMENO_POSO;
  CLOSE C4;
  
  RETURN :CP_ENSOMATOSH_KYRIAS;
  EXCEPTION WHEN OTHERS THEN RETURN NULL;
  
end;

