      function CF_XRONOS_ANAGNORISHS_KEFormul return Char is

CURSOR C1 IS
 SELECT   A.METAFEROMENO_KEFALAIO ,
          A.TELIKO_METAFEROMENO_KEFALAIO ,
          A.KEFALAIO_ENSOMATOSIS ,
          A.ETH_ANAGNORISIS,
          A.POSO_EPISTROFIS , 
					A.TOTAL_YEARS_EE
					--,A.SID
   FROM   PEN_ANALOGIST_ISODYNAMO_HD A					
  WHERE   A.STATUS = '1'
  AND     A.SID            = :P_SID
  AND     A.INS_INSURED_ID = :P_INSURED_ID; 

L_DAYS NUMBER;

begin
	
   OPEN C1;
   FETCH C1 INTO :CP_METAFER_KEFALAIO,
                 :CP_TELIKO_METAFER_KEFALAIO,
				         :CP_KEFAL_ENSOMAT,
				         :CP_ETH_ANAGNORISIS,
				         :CP_POSO_EPISTROFIS , 
								 :CP_TOTAL_YEARS_EE;
   CLOSE C1;  
      
   IF :CP_KEFAL_ENSOMAT > :CP_METAFER_KEFALAIO THEN
		  
		  :CP_TOTAL_YY  := null;
		  :CP_TOTAL_MM  := null;
		  :CP_TOTAL_DD  := null;
		  
		  L_DAYS := NVL(NVL(:CP_ETH_ANAGNORISIS,0) *300,0) ;
		  
		  com_util_days.convdaysinyearsmontsdays(pisumofdays   => L_DAYS,
		                                         pidaysofmonth => 25,
		                                         poyears       => :CP_TOTAL_YY,
		                                         pomonths      => :CP_TOTAL_MM,
		                                         podays        => :CP_TOTAL_DD);
		  
	   -- CHRYS 13/1/2026
	   IF ROUND(:CP_TOTAL_DD) = 25 THEN 
	   		:CP_TOTAL_DD := 0;
	   		:CP_TOTAL_MM := :CP_TOTAL_MM +1;
	   	
	   		IF ROUND(:CP_TOTAL_MM) = 12 THEN
	   			:CP_TOTAL_MM := 0;
	   			:CP_TOTAL_YY := :CP_TOTAL_YY +1;
	   		END IF;
	   END IF;
	   -- END CHRYS 13/1/2026

   ELSE
   	
   	  :CP_TOTAL_YY  := null;
		  :CP_TOTAL_MM  := null;
		  :CP_TOTAL_DD  := null;
		  
		  L_DAYS := NVL(NVL(:CP_XRONOS_ANAGNORISHS,0) *300,0) ;
		  PENBAT_DEBUGING(':CP_XRONOS_ANAGNORISHS='||:CP_XRONOS_ANAGNORISHS, 'CHRYS_13012026');
		  PENBAT_DEBUGING('L_DAYS='||L_DAYS, 'CHRYS_13012026');
		  com_util_days.convdaysinyearsmontsdays(pisumofdays   => L_DAYS,
		                                         pidaysofmonth => 25,
		                                         poyears       => :CP_TOTAL_YY,
		                                         pomonths      => :CP_TOTAL_MM,
		                                         podays        => :CP_TOTAL_DD);
		  
   PENBAT_DEBUGING(':CP_TOTAL_DD='||:CP_TOTAL_DD, 'CHRYS_13012026');
	   -- CHRYS 13/1/2026
	   IF ROUND(:CP_TOTAL_DD) = 25 THEN 
	   		:CP_TOTAL_DD := 0;
	   		:CP_TOTAL_MM := :CP_TOTAL_MM +1;
	   	
	   		IF ROUND(:CP_TOTAL_MM) = 12 THEN
	   			:CP_TOTAL_MM := 0;
	   			:CP_TOTAL_YY := :CP_TOTAL_YY +1;
	   		END IF;
	   END IF;
	   -- END CHRYS 13/1/2026
   
   END IF;
   PENBAT_DEBUGING(':CP_TOTAL_DD 2='||:CP_TOTAL_DD, 'CHRYS_13012026');
   RETURN (:CP_METAFER_KEFALAIO);
   EXCEPTION WHEN OTHERS THEN RETURN NULL;
end;

function CF_ASFAL_XRONOIFormula return Char is
CURSOR C1 IS select a.value from pen_dec_fact_types_instance a, PEN_ACCOUNT B where a.status = '1' and a.ins_insured_id = :p_insured_id AND B.DI_DT_DOCUMENT_TYPE_DEC_CODE = a.di_document_type_dec_coce_sr AND B.DI_DT_DEC_UNIT_CODE = a.di_dec_unit_code_sr AND B.DI_DT_DECISION_YEAR = a.di_decision_year_sr AND B.DI_DEC_INCR_SEQ_NO = a.di_dec_incr_seq_no_sr AND B.ACCOUNT_NO = :P_ACCOUNT_NO_KYRIA and a.title_code = '01865' and a.dec_fact_type_code = '01867' ;
CURSOR C2 IS select a.value from pen_dec_fact_types_instance a, PEN_ACCOUNT B where a.status = '1' and a.ins_insured_id = :p_insured_id AND B.DI_DT_DOCUMENT_TYPE_DEC_CODE = a.di_document_type_dec_coce_sr AND B.DI_DT_DEC_UNIT_CODE = a.di_dec_unit_code_sr AND B.DI_DT_DECISION_YEAR = a.di_decision_year_sr AND B.DI_DEC_INCR_SEQ_NO = a.di_dec_incr_seq_no_sr AND B.ACCOUNT_NO = :P_ACCOUNT_NO_KYRIA and a.title_code = '01865' and a.dec_fact_type_code = '01868' ;
CURSOR C3 IS select a.value from pen_dec_fact_types_instance a, PEN_ACCOUNT B where a.status = '1' and a.ins_insured_id = :p_insured_id AND B.DI_DT_DOCUMENT_TYPE_DEC_CODE = a.di_document_type_dec_coce_sr AND B.DI_DT_DEC_UNIT_CODE = a.di_dec_unit_code_sr AND B.DI_DT_DECISION_YEAR = a.di_decision_year_sr AND B.DI_DEC_INCR_SEQ_NO = a.di_dec_incr_seq_no_sr AND B.ACCOUNT_NO = :P_ACCOUNT_NO_KYRIA and a.title_code = '01854' and a.dec_fact_type_code = '01855' ;
begin OPEN C1; FETCH C1 INTO :CP_ASFAL_MIN_DATE; CLOSE C1;
OPEN C2; FETCH C2 INTO :CP_ASFAL_MAX_DATE; CLOSE C2;
OPEN C3; FETCH C3 INTO :CP_ASFAL_YY; CLOSE C3;
RETURN (:CP_ASFAL_YY); EXCEPTION WHEN OTHERS THEN RETURN NULL; end;

