      function F_18FormatTrigger return Boolean is
V_STRING VARCHAR2(2000);

begin
  V_STRING :=  :FULLNAME|| ' με A.Σ :'||:P_INSURED_ID||' / '||'ΑΜΚΑ:'||:AMKA_ID ||' Αρ.Προσωπικού στην ΕΕ/Δ.Ο. '; --||:PROTOCOL_DETAILS;
